const testPrices = $items().map(i => i.json);
const validatedInput = $node["Validate input"].json;

// Initialize array for matched tests
let matchedTests = [];
let totalTestCost = 0;

// Loop through all tests in RFP summary
if (Array.isArray(validatedInput.rfp_summary)) {
  for (const testName of validatedInput.rfp_summary) {
    // Find the test in the testPrices sheet
    const test = testPrices.find(t => t.Test_Name === testName);

    if (test) {
      matchedTests.push({
        test_name: test.Test_Name,
        test_type: test.Test_Type,
        unit_cost: Number(test.Unit_Cost),
        duration_days: test["Duration (days)"],
      });

      totalTestCost += Number(test.Unit_Cost);
    } else {
      console.log(`⚠️ Test not found in sheet: ${testName}`);
    }
  }
}

// Prepare final output
const output = {
  rfp_id: validatedInput.rfp_id,
  matched_tests: matchedTests,
  total_test_cost: totalTestCost
};


return [{ json: output }];

