let priceMatches = [];

// --- Step 3: Loop through each line item in RFP technical_table ---
for (const line of validatedInput.technical_table) {
  const recommendedProducts = line.recommended;

  // Find matching SKUs in the Excel data
  const matched = recommendedProducts.map(rec => {
    const product = productPrices.find(p => p.json.SKU_ID == rec.sku);

    // If found, return pricing + spec info
    if (product) {
      return {
        sku: rec.sku,
        spec_match: rec.spec_match,
        product_name: product.json.Product_Name,
        base_price: product.json.Base_Price,
        unit: product.json.Unit_of_Measure,
        product_type: product.json.Product_Type,
        total_price: Number(product.json.Base_Price) * Number(line.quantity)
      };
    } else {
      return {
        sku: rec.sku,
        spec_match: rec.spec_match,
        product_name: "NOT FOUND",
        base_price: null,
        unit: null,
        product_type: null,
        total_price: 0
      };
    }
  });

  // Push results for this line item
  priceMatches.push({
    line_id: line.line_id,
    scope_item: line.scope_item,
    quantity: line.quantity,
    recommended_pricing: matched
  });
}

// --- Step 4: Output in n8n format ---
return [
  {
    json: {
      rfp_id: validatedInput.rfp_id,
      pricing_table: priceMatches
    }
  }
];

// Collect all input items (n8n gives them one-by-one)
const allInputs = $input.all();

// Find the pricing and test data items
let pricingData = allInputs.find(item => item.json.pricing_table);
let testData = allInputs.find(item => item.json.matched_tests);

// Safety check
if (!pricingData && !testData) {
  return [{ json: { error: "No pricing_table or matched_tests found in input" } }];
}

// Extract their JSON contents
pricingData = pricingData ? pricingData.json : {};
testData = testData ? testData.json : {};

// --- Prepare Tables ---
let structuredProductTable = [];   // <-- 🆕 Structured table per line_id
let testPricingTable = [];
let totalMaterialCost = 0;
let totalTestCost = 0;

// --- Product Pricing Table (structured) ---
if (pricingData.pricing_table) {
  for (const line of pricingData.pricing_table) {
    const skuEntries = [];

    for (const rec of line.recommended_pricing) {
      skuEntries.push({
        sku_id: rec.sku,
        product_name: rec.product_name,
        spec_match: rec.spec_match,
        base_price: rec.base_price,
        total_price: rec.total_price,
        unit: rec.unit,
        product_type: rec.product_type
      });
    }

    // Add only the top SKU (first one) to total material cost
    if (line.recommended_pricing?.length > 0) {
      totalMaterialCost += Number(line.recommended_pricing[0].total_price);
    }

    // 🆕 Push structured object for each line_id
    structuredProductTable.push({
      line_id: line.line_id,
      scope_item: line.scope_item,
      quantity: line.quantity,
      recommended_pricing: skuEntries
    });
  }
}

// --- Test Table ---
if (testData.matched_tests) {
  for (const t of testData.matched_tests) {
    testPricingTable.push({
      test_name: t.test_name,
      test_type: t.test_type,
      unit_cost: t.unit_cost,
      duration_days: t.duration_days
    });
    totalTestCost += Number(t.unit_cost);
  }
}

// --- Totals ---
const overallCost = totalMaterialCost + totalTestCost;

// --- Final Output ---
return [
  {
    json: {
      rfp_id: pricingData.rfp_id || testData.rfp_id || "Unknown",
      product_pricing_table: structuredProductTable,
      test_pricing_table: testPricingTable,
      summary: {
        total_material_cost: totalMaterialCost,
        total_test_cost: totalTestCost,
        overall_project_cost: overallCost
      }
    }
  }
];
